  const isHealthy = diagnosis.status === 'Healthy';

  const playSummary = () => {
    if ('speechSynthesis' in window) {
      window.speechSynthesis.cancel();
      const utterance = new SpeechSynthesisUtterance(diagnosis.localLanguageSummary);
      utterance.rate = 0.9;
      utterance.onstart = () => setIsPlaying(true);
      utterance.onend = () => setIsPlaying(false);
      window.speechSynthesis.speak(utterance);
    }
  };

  return (
    <div className="w-full space-y-4 animate-in fade-in slide-in-from-bottom-6 duration-700">
      {/* Summary Audio Banner */}
      <div className="bg-emerald-600 text-white rounded-3xl p-6 shadow-xl flex items-center justify-between border-4 border-white">
        <div className="flex-1">
          <p className="text-xs font-bold uppercase tracking-widest opacity-80 mb-1">Audio Assistant</p>
          <p className="text-lg font-bold leading-tight line-clamp-2 italic">
            "{diagnosis.localLanguageSummary}"
          </p>
        </div>
        <button 
          onClick={playSummary}
          className={`ml-4 h-16 w-16 rounded-full flex items-center justify-center transition-all ${
