import { GoogleGenAI } from "@google/genai";
import { PlantDiagnosis, Language } from "../types";

export const diagnosePlant = async (
  imageBase64: string, 
  location?: { latitude: number; longitude: number },
  language: Language = 'English',
  isPfumvudzaMode: boolean = false
): Promise<PlantDiagnosis> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/jpeg',
            data: imageBase64,
          },
        },
        {
          text: `Act as a senior Zimbabwean agricultural expert. 
          Analyze this plant image and detect issues.

          CONFIG:
          - Current Language: ${language}
          - Pfumvudza Mode: ${isPfumvudzaMode ? 'ON' : 'OFF'}
          - Target Location: Zimbabwe (near ${location?.latitude}, ${location?.longitude})

          TASKS:
          1. Identify plant and condition.
          2. Find 3 real nearest agro-dealers in Zimbabwe (Agricura, Windmill, ZFC, Farm & City) that stock the cure.
          3. Provide a 2-sentence summary of the diagnosis and cure specifically in ${language}.

          FORMAT: Return ONLY a valid JSON object.
          {
            "plantName": string,
            "scientificName": string,
            "status": "Healthy" | "Diseased" | "Stressed",
            "confidenceScore": number,
            "conditionName": string,
            "description": string,
            "immediateActions": string[],
            "organicTreatment": string,
            "chemicalTreatment": string,
            "preventionTips": string[],
            "localLanguageSummary": string,
            "suppliers": [{ "name": string, "distance": string, "directionsUrl": string }]
          }`
        }
      ]
    },
    config: {
      tools: [{ googleMaps: {} }],
      toolConfig: {
        retrievalConfig: {
          latLng: location ? {
            latitude: location.latitude,
            longitude: location.longitude
          } : undefined
        }
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("No response from AI");

  try {
    const cleanJson = text.replace(/```json/g, '').replace(/```/g, '').trim();
    const parsed = JSON.parse(cleanJson) as PlantDiagnosis;

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks && parsed.suppliers) {
      parsed.suppliers = parsed.suppliers.map((s) => {
        const chunk = groundingChunks.find((c: any) => 
          c.maps?.title?.toLowerCase().includes(s.name.toLowerCase()) || 
          s.name.toLowerCase().includes(c.maps?.title?.toLowerCase())
        );
        if (chunk?.maps?.uri) return { ...s, directionsUrl: chunk.maps.uri };
        return s;
      });
    }

    return parsed;
  } catch (e) {
    console.error("Parse Error:", e, text);
    throw new Error("Unable to read diagnosis format.");
  }
};

export const translateText = async (text: string, targetLanguage: Language): Promise<string> => {
  if (targetLanguage === 'English') return text;

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Translate the following farming text into ${targetLanguage}. Keep the tone professional but community-friendly: "${text}"`,
  });

  return response.text?.trim() || text;
};

import React from 'react';
import { AlertCircle, Zap } from 'lucide-react';
import { CommunityPost } from '../types';

interface OutbreakTickerProps {
  posts: CommunityPost[];
}

const OutbreakTicker: React.FC<OutbreakTickerProps> = ({ posts }) => {
  // Logic: Find if 3 or more posts in same district have same disease
  const reportCounts: Record<string, number> = {};

  posts.forEach(p => {
    if (p.diagnosis.status !== 'Healthy') {
      const key = `${p.district}-${p.diagnosis.conditionName}`;
      reportCounts[key] = (reportCounts[key] || 0) + 1;
    }
  });

  const activeOutbreaks = Object.entries(reportCounts)
    .filter(([_, count]) => count >= 2) // Reduced to 2 for demo purposes
    .map(([key]) => {
      const [district, condition] = key.split('-');
      return { district, condition };
    });

  if (activeOutbreaks.length === 0) {
    return (
      <div className="bg-emerald-50 border-2 border-emerald-100 p-3 rounded-2xl flex items-center gap-3 animate-in fade-in slide-in-from-top-2">
        <div className="bg-emerald-500 p-1.5 rounded-lg text-white">
          <Zap size={16} />
        </div>
        <p className="text-xs font-bold text-emerald-800">
          ALL CLEAR: No major outbreaks detected in your current region.
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-2">
      {activeOutbreaks.map((outbreak, idx) => (
        <div key={idx} className="bg-red-600 text-white p-4 rounded-2xl flex items-center gap-4 shadow-lg animate-pulse border-4 border-red-400">
          <AlertCircle size={24} className="shrink-0" />
          <div>
            <p className="text-xs font-black uppercase tracking-widest opacity-80 leading-none mb-1">Regional Outbreak Alert</p>
            <p className="text-sm font-bold">
              High incidence of <span className="underline decoration-2">{outbreak.condition}</span> reported in {outbreak.district} District!
            </p>
          </div>
        </div>
      ))}
    </div>
  );
};

export default OutbreakTicker;

